    rasxodVsSellComparisonListFiltered() {
      if (!this.rasxodVsSellComparisonList || this.rasxodVsSellComparisonList.length === 0) {
        return [];
      }
      // Farq 0 bo'lganlarni filter qilish
      return this.rasxodVsSellComparisonList.filter(item => item.diff !== 0);
    },
    
    tableTotals() {
      if (!this.searchlist || this.searchlist.length === 0) {
        return {
          nachalniyOstatok: 0,
          kirim: 0,
          chiqim: 0,
          ostatka: 0
        };
      }

      return this.searchlist
        // 🔹 CATEGORY FILTER
        .filter(row => {
          return (
            this.select_category_id === null ||
            (row.product && row.product.bot_id === this.select_category_id)
          );
        })
        // 🔹 TOTALS CALCULATION
        .reduce((totals, row) => {
          const nachalniyOstatok = (row.currentQty - row.kirim + row.chiqim);

          totals.nachalniyOstatok +=
            (nachalniyOstatok > -1 && nachalniyOstatok < 0) ? 0 : nachalniyOstatok;

          totals.kirim +=
            (row.kirim > -1 && row.kirim < 0) ? 0 : row.kirim;

          totals.chiqim +=
            (row.chiqim > -1 && row.chiqim < 0) ? 0 : row.chiqim;

          totals.ostatka +=
            (row.currentQty > -1 && row.currentQty < 0) ? 0 : row.currentQty;

          return totals;
        }, {
          nachalniyOstatok: 0,
          kirim: 0,
          chiqim: 0,
          ostatka: 0
        });
      }
  },
