    async loadSkladCountDiff(){
      try{
        // auth_user_creator_id = 1 bo'lgan diff larni yuklash (sklad_count sahifasidan yozilgan)
        const res = await fetch(
          this.$store.state.hostname +
          '/TegirmonSkladDiffControler/get-by-date?date=' +
          this.Start_time +
          '&sklad_id=' +
          this.sklad_id
        );
        const data = await res.json();
        
        if(res.status == 200 || res.status == 201){
          // auth_user_creator_id = 1 bo'lganlarini filter qilish
          const skladCountDiffs = data.filter(diff => diff.auth_user_creator_id === 1);
          
          if(skladCountDiffs.length > 0){
            // Diff lardagi qty larni searchlist ga yozish
            const diffMap = {};
            skladCountDiffs.forEach(diff => {
              diffMap[diff.tegirmonProductId] = diff.qty;
            });
            this.counter_user_id = skladCountDiffs[0].auth_user_updator_id;
            // searchlist ni yangilash
            this.searchlist = this.OstatkaList.map(x => {
              const qty = diffMap[x.productId] !== undefined ? diffMap[x.productId] : x.currentQty;
              return {
                chiqim: x.chiqim,
                currentQty: x.currentQty,
                kirim: x.kirim,
                product: x.product,
                productId: x.productId,
                productName: x.productName,
                unitM: x.unitM,
                new_qty: qty,
                new_qty_str: qty.toFixed().toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 '),
                diff_qty: qty - x.currentQty,
                diff_qty_str: (qty - x.currentQty).toFixed().toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')
              };
            });
          }
          else{
            this.sklad_diff = true;
            this.update_status = false;
            this.diff_info_show = false;
            this.searchlist = this.OstatkaList.map(x => ({
              chiqim: x.chiqim,
              currentQty: x.currentQty,
              kirim: x.kirim,
              product: x.product,
              productId: x.productId,
              productName: x.productName,
              unitM: x.unitM,
              new_qty: 0,
              new_qty_str: '0',
              diff_qty: 0,
              diff_qty_str: '0',
            }));
          }
        }
      }
      catch(error){
        console.log('Sklad count diff yuklashda xatolik:', error)
      }
    },


