    funcDiffQty(n,index){
      console.log(n)
      console.log(index)
      var tols = ''
      for(let i=0; i<n.length; i++){
        if(n[i] != ' '){
          tols += n[i];
        }
      }
      if(tols[tols.length-1] != '0' && tols[tols.length-1] != '1' && tols[tols.length-1] != '2' && tols[tols.length-1] != '3' && tols[tols.length-1] != '4' && 
        tols[tols.length-1] != '5' && tols[tols.length-1] != '6' && tols[tols.length-1] != '7' && tols[tols.length-1] != '8' && tols[tols.length-1] != '9'){
        tols = tols.slice(0,tols.length-1)
       }
      this.searchlist[index].new_qty_str = tols.replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
      var temp = ''
      for(let i=0; i<this.searchlist[index].new_qty_str.length; i++){
        if(this.searchlist[index].new_qty_str[i] != ' '){
          temp += this.searchlist[index].new_qty_str[i];
        }
      }
      if(temp == ''){
        this.searchlist[index].new_qty = 0;
      }
      else{
        this.searchlist[index].new_qty = parseFloat(temp);
      }
      console.log(this.searchlist[index])
      console.log(this.searchlist)
      this.searchlist[index].diff_qty = this.searchlist[index].new_qty - this.searchlist[index].currentQty;
      this.searchlist[index].diff_qty_str = this.formatNumber(this.searchlist[index].diff_qty).toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
    },

    formatNumber(value) {
      if (value === null || value === undefined || isNaN(value)) {
        return 0;
      }
      // 2 ta onlik raqamgacha formatlash
      const num = parseFloat(value);
      if (isNaN(num)) {
        return 0;
      }
      // Kasr qismini 2 ta raqamgacha cheklash
      return parseFloat(num.toFixed(2));
    },
    formatCategoryNumber(value) {
      if (value === null || value === undefined || isNaN(value)) {
        return '0';
      }
      const num = parseFloat(value);
      if (isNaN(num)) {
        return '0';
      }
      // Agar butun son bo'lsa, faqat butun qismni ko'rsatish
      if (num % 1 === 0) {
        return num.toString().replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1 ');
      }
      // Kasr qismi bo'lsa, 2 ta onlik raqamgacha formatlash
      const formatted = num.toFixed(2);
      // Butun qism va kasr qismini alohida formatlash
      const parts = formatted.split('.');
      const integerPart = parts[0].replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1 ');
      // Agar kasr qismi faqat nollar bo'lsa, uni ko'rsatmaymiz
      const decimalPart = parts[1] && parseFloat(parts[1]) > 0 ? '.' + parts[1] : '';
      return integerPart + decimalPart;
    },
    formatDiffQty(value) {
      if (value == null || value == undefined || isNaN(value)) {
        return '0';
      }
      // Agar butun son bo'lsa
      if (value % 1 === 0) {
        return value.toString().replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1 ');
      } else {
        // Kasr qismi bo'lsa, 2 ta onlik raqamgacha kesamiz
        const formatted = parseFloat(value.toFixed(2));
        // Butun qism va kasr qismini alohida formatlaymiz
        const parts = formatted.toString().split('.');
        const integerPart = parts[0].replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1 ');
        const decimalPart = parts[1] ? '.' + parts[1] : '';
        return integerPart + decimalPart;
      }
    },

