    },
    ensureHtml2Pdf() {
      return new Promise((resolve, reject) => {
        if (window.html2pdf) {
          resolve(window.html2pdf);
          return;
        }

        const existing = document.getElementById("html2pdf-script");
        if (existing) {
          existing.addEventListener("load", () => resolve(window.html2pdf));
          existing.addEventListener("error", () => reject(new Error("html2pdf load failed")));
          return;
        }

        const script = document.createElement("script");
        script.id = "html2pdf-script";
        script.src = "https://cdn.jsdelivr.net/npm/html2pdf.js@0.10.1/dist/html2pdf.bundle.min.js";
        script.onload = () => resolve(window.html2pdf);
        script.onerror = () => reject(new Error("html2pdf load failed"));
        document.body.appendChild(script);
      });
    },
    async savePdf() {
      const source = document.getElementById("sklad_ostatka");
      if (!source) return;

      const tempContainer = document.createElement("div");
      tempContainer.style.position = "fixed";
      tempContainer.style.left = "-10000px";
      tempContainer.style.top = "0";
      tempContainer.style.background = "#fff";
      const a4WidthPx = 1100; // A4 landscape at 96dpi
      tempContainer.style.width = `${a4WidthPx}px`;

      const wrapper = document.createElement("div");
      wrapper.style.width = `${a4WidthPx}px`;
      wrapper.style.paddingBottom = "20px";

      const dateTitle = document.createElement("div");
      dateTitle.style.fontSize = "12px";
      dateTitle.style.color = "#3a4b52";
      dateTitle.style.margin = "4px 0 8px";
      dateTitle.textContent = `${this.Start_time || ''} ${this.sklad_name || ''}`.trim();
      wrapper.appendChild(dateTitle);

      const clone = source.cloneNode(true);
      clone.style.width = `${a4WidthPx}px`;
      wrapper.appendChild(clone);

      const pageStyle = document.createElement("style");
      pageStyle.textContent = `
        .myTableSkladDashboard { page-break-before: auto; }
        .myTableSkladDashboard { page-break-inside: auto; }
        .myTableSkladDashboard tr { page-break-inside: avoid; page-break-after: auto; break-inside: avoid; }
        .myTableSkladDashboard td, .myTableSkladDashboard th { page-break-inside: avoid; break-inside: avoid; }
      `;
      wrapper.appendChild(pageStyle);

      tempContainer.appendChild(wrapper);
      document.body.appendChild(tempContainer);

      try {
        this.isPdfGenerating = true;
        await this.$nextTick();
        await new Promise(resolve => setTimeout(resolve, 300));
        const now = new Date();
        const pad = (value) => String(value).padStart(2, "0");
        const timestamp = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}-${pad(now.getMinutes())}-${pad(now.getSeconds())}`;
        const skladName = this.sklad_name || "Sklad";
        const html2pdf = await this.ensureHtml2Pdf();
        await html2pdf()
          .from(wrapper)
          .set({
            margin: 3,
            filename: `📦 ${skladName} (${timestamp}).pdf`,
            pagebreak: { mode: ['css', 'legacy'], avoid: '.myTableSkladDashboard tr' },
            html2canvas: { scale: 2.5, useCORS: true, backgroundColor: "#ffffff" },
            jsPDF: { unit: "mm", format: "a4", orientation: "landscape" }
          })
          .save();
      } finally {
        document.body.removeChild(tempContainer);
        this.isPdfGenerating = false;
      }
    },
    async openProductHistoryModal(row, type) {
      // type: 1 - kirim, 2 - chiqim, null - hammasi
      this.productHistoryLoading = true;
      this.productHistoryModalShow = true;
      
      let typeName = type === 1 ? 'Kirim' : type === 2 ? 'Chiqim' : 'Barcha';
      this.productHistoryModalTitle = `${row.productName} - ${typeName} tarixi`;
      
      let url = this.$store.state.hostname + `/TegirmonSkladHistory/getProductHistoryDetails?product_id=${row.productId}`;
      
      // Sklad filter
      if (this.sklad_id) {
        url += `&sklad_id=${this.sklad_id}`;
      }
      
      // Date filter
      if (this.Start_time) {
        url += `&date=${this.Start_time}`;
      }
      
      // Type filter
      if (type) {
        url += `&type=${type}`;
      }

      try {
        const res = await fetch(url);
        if (res.status === 200 || res.status === 201) {
          const data = await res.json();
          this.productHistoryList = data;
        } else {
          this.$refs.message.error("Ma'lumotlarni yuklashda xatolik yuz berdi");
          this.productHistoryList = [];
        }
      } catch (error) {
        console.error('Product history fetch error:', error);
        this.$refs.message.error("Serverda uzilish bor. Qayta urinib ko'ring !");
        this.productHistoryList = [];
      } finally {
        this.productHistoryLoading = false;
      }
    },
    formatDate(dateString) {
      if (!dateString) return '';
      const date = new Date(dateString);
      const day = String(date.getDate()).padStart(2, '0');
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const year = date.getFullYear();
      const hours = String(date.getHours()).padStart(2, '0');
      const minutes = String(date.getMinutes()).padStart(2, '0');
      return `${day}.${month}.${year} ${hours}:${minutes}`;
    },
